SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS auth_sessions; DROP TABLE IF EXISTS attendance_logs; DROP TABLE IF EXISTS companions; DROP TABLE IF EXISTS visits; DROP TABLE IF EXISTS visitors; DROP TABLE IF EXISTS guests; DROP TABLE IF EXISTS event_sessions; DROP TABLE IF EXISTS events; DROP TABLE IF EXISTS guest_types; DROP TABLE IF EXISTS users; DROP TABLE IF EXISTS settings;
SET FOREIGN_KEY_CHECKS = 1;
CREATE TABLE settings (setting_key VARCHAR(80) PRIMARY KEY, setting_value TEXT NOT NULL, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE users (id VARCHAR(40) PRIMARY KEY, name VARCHAR(160) NOT NULL, role VARCHAR(80) NOT NULL, email VARCHAR(190) NOT NULL UNIQUE, password_hash VARCHAR(255) NULL, active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE auth_sessions (id VARCHAR(40) PRIMARY KEY, user_id VARCHAR(40) NOT NULL, token_hash CHAR(64) NOT NULL UNIQUE, expires_at DATETIME NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_auth_sessions_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, INDEX idx_auth_sessions_user (user_id), INDEX idx_auth_sessions_expires (expires_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE guest_types (id VARCHAR(40) PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE, color VARCHAR(20) NOT NULL DEFAULT '#1d4ed8', sort_order INT NOT NULL DEFAULT 100) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE events (id VARCHAR(40) PRIMARY KEY, name VARCHAR(220) NOT NULL, description TEXT NULL, starts_on DATE NOT NULL, ends_on DATE NOT NULL, location VARCHAR(180) NOT NULL, status ENUM('borrador','activo','finalizado') NOT NULL DEFAULT 'borrador', requires_confirmation TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_events_dates (starts_on, ends_on), INDEX idx_events_status (status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE event_sessions (id VARCHAR(40) PRIMARY KEY, event_id VARCHAR(40) NOT NULL, name VARCHAR(180) NOT NULL, session_date DATE NOT NULL, starts_at TIME NOT NULL, ends_at TIME NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_sessions_event FOREIGN KEY (event_id) REFERENCES events(id) ON DELETE CASCADE, INDEX idx_sessions_event_date (event_id, session_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE guests (id VARCHAR(40) PRIMARY KEY, event_id VARCHAR(40) NOT NULL, guest_type_id VARCHAR(40) NOT NULL, name VARCHAR(180) NOT NULL, document_id VARCHAR(50) NOT NULL, position VARCHAR(140) NULL, institution VARCHAR(180) NULL, email VARCHAR(190) NULL, confirmation ENUM('aceptado','tentativo','rechazado','pendiente') NOT NULL DEFAULT 'pendiente', invitation_sent_at DATETIME NULL, arrival_at DATETIME NULL, departure_at DATETIME NULL, is_walk_in TINYINT(1) NOT NULL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_guests_event FOREIGN KEY (event_id) REFERENCES events(id) ON DELETE CASCADE, CONSTRAINT fk_guests_type FOREIGN KEY (guest_type_id) REFERENCES guest_types(id), INDEX idx_guests_event (event_id), INDEX idx_guests_document (document_id), INDEX idx_guests_confirmation (confirmation)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE attendance_logs (id VARCHAR(40) PRIMARY KEY, guest_id VARCHAR(40) NOT NULL, event_session_id VARCHAR(40) NULL, action ENUM('entrada','salida') NOT NULL, happened_at DATETIME NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_attendance_guest FOREIGN KEY (guest_id) REFERENCES guests(id) ON DELETE CASCADE, CONSTRAINT fk_attendance_session FOREIGN KEY (event_session_id) REFERENCES event_sessions(id) ON DELETE SET NULL, INDEX idx_attendance_guest_time (guest_id, happened_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE visitors (id VARCHAR(40) PRIMARY KEY, document_id VARCHAR(50) NOT NULL UNIQUE, name VARCHAR(180) NOT NULL, position VARCHAR(140) NULL, institution VARCHAR(180) NULL, phone VARCHAR(50) NULL, email VARCHAR(190) NULL, photo_url VARCHAR(255) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_visitors_name (name), INDEX idx_visitors_institution (institution)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE visits (id VARCHAR(40) PRIMARY KEY, visitor_id VARCHAR(40) NOT NULL, area VARCHAR(140) NOT NULL, reason VARCHAR(255) NOT NULL, entry_at DATETIME NOT NULL, exit_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_visits_visitor FOREIGN KEY (visitor_id) REFERENCES visitors(id) ON DELETE CASCADE, INDEX idx_visits_entry (entry_at), INDEX idx_visits_exit (exit_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE companions (id VARCHAR(40) PRIMARY KEY, visit_id VARCHAR(40) NOT NULL, name VARCHAR(180) NOT NULL, document_id VARCHAR(50) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_companions_visit FOREIGN KEY (visit_id) REFERENCES visits(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
